const fs = require('fs');
const path = require('path');

const partners = [
  // Previous & Image 1
  { name: "Microsoft", color: "#0078D4" },
  { name: "Dell EMC", filename: "dellemc", color: "#007DB8" }, // Was Dell
  { name: "Intel", color: "#0071C5" },
  { name: "IBM", color: "#0530AD" },
  { name: "Cisco", color: "#049FD9" },
  { name: "HPE", color: "#01A982" },
  { name: "Citrix", color: "#4B5563" },
  { name: "Star2Star", color: "#6B21A8" },
  { name: "KnowBe4", color: "#F58220" },
  { name: "AWS", color: "#FF9900" },
  { name: "Google Cloud", filename: "googlecloud", color: "#4285F4" },
  { name: "A10 Networks", filename: "a10", color: "#0083CB" },
  { name: "Oracle", color: "#C74634" },
  { name: "Barracuda", color: "#0064FA" },
  { name: "Check Point", filename: "checkpoint", color: "#EC1C24" },
  { name: "F5", color: "#E31F28" },

  // Image 2
  { name: "Fortinet", color: "#C01818" },
  { name: "RSA", color: "#BE2137" },
  { name: "Symantec", color: "#FFC700" }, // often yellow/black
  { name: "Trend Micro", filename: "trendmicro", color: "#D71920" },
  { name: "Unitrends", color: "#000000" },
  { name: "VMware", color: "#607078" },
  { name: "Webroot", color: "#59B846" },
  { name: "Lenovo", color: "#E2231A" },

  // Image 3
  { name: "Skout", color: "#4B5563" }, // Generic dark

  // Legacy/Others in list but maybe not in images (Keep or Remove? User said "All partners logos... sent to you". I should probably keep existing prominent ones if they make sense, but prioritize the images.)
  // Keeping RingCentral and Meraki from previous list if they are major, but maybe user wants EXACTLY what is in images. 
  // Image 1 has Cisco, which covers Meraki broadly. RingCentral is not in images? Star2Star is there. 
  // I will stick to the ones found in images + keep existing ones if they are not duplicates.
  // RingCentral was in my previous list but not in these images. I'll include it just in case, or drop it to match images strictly. 
  // User said "All partners... sent to you" implying "This is the list". I will stick to the identifiable ones in images + existing ones that overlap.
  { name: "RingCentral", color: "#FF5200" }, // Kept for safety
  { name: "Cisco Meraki", filename: "meraki", color: "#67B346" } // Kept
];

const outDir = path.join(__dirname, 'public', 'partners');

if (!fs.existsSync(outDir)) {
  fs.mkdirSync(outDir, { recursive: true });
}

partners.forEach(p => {
  const filename = (p.filename || p.name.toLowerCase().replace(/\s+/g, '')) + '.svg';
  const svgContent = `
<svg width="200" height="100" viewBox="0 0 200 100" xmlns="http://www.w3.org/2000/svg">
  <rect width="200" height="100" fill="white" fill-opacity="0"/>
  <text x="50%" y="50%" dominant-baseline="middle" text-anchor="middle" font-family="Arial, sans-serif" font-weight="bold" font-size="${p.name.length > 10 ? '20' : '24'}" fill="${p.color}">
    ${p.name}
  </text>
</svg>`.trim();

  fs.writeFileSync(path.join(outDir, filename), svgContent);
  console.log(`Generated ${filename}`);
});

"use client";

import PageHero from "@/components/PageHero";
import { useTranslations } from "next-intl";
import { Server, Database, Cable, CheckCircle2 } from "lucide-react";
import { motion } from "framer-motion";

export default function AISolutionsPage() {
    const t = useTranslations("AI_Page");

    const sections = [
        {
            id: "server",
            icon: Server,
            color: "text-blue-500",
            imgGradient: "from-blue-500/20 to-purple-500/20"
        },
        {
            id: "datacenter",
            icon: Database,
            color: "text-purple-500",
            imgGradient: "from-purple-500/20 to-pink-500/20"
        },
        {
            id: "connectivity",
            icon: Cable,
            color: "text-cyan-500",
            imgGradient: "from-cyan-500/20 to-blue-500/20"
        }
    ];

    return (
        <div className="min-h-screen bg-white dark:bg-black">
            <PageHero
                title={t("hero_title")}
                subtitle={t("hero_subtitle")}
                bgGradient="from-indigo-900/40 via-black to-black"
            />

            <div className="container mx-auto px-4 py-24 space-y-32">
                {sections.map((section, index) => (
                    <motion.div
                        key={section.id}
                        initial={{ opacity: 0, y: 40 }}
                        whileInView={{ opacity: 1, y: 0 }}
                        transition={{ duration: 0.6, delay: index * 0.1 }}
                        viewport={{ once: true }}
                        className={`flex flex-col ${index % 2 === 1 ? 'lg:flex-row-reverse' : 'lg:flex-row'} items-center gap-12 lg:gap-20`}
                    >
                        {/* Text Content */}
                        <div className="flex-1 space-y-6">
                            <div className={`inline-flex p-3 rounded-2xl bg-zinc-100 dark:bg-zinc-900 ${section.color}`}>
                                <section.icon className="w-8 h-8" />
                            </div>
                            <h2 className="text-3xl md:text-4xl font-bold text-zinc-900 dark:text-white">
                                {t(`sections.${section.id}.title`)}
                            </h2>
                            <p className="text-lg text-zinc-600 dark:text-zinc-400 leading-relaxed">
                                {t(`sections.${section.id}.description`)}
                            </p>
                            <ul className="space-y-3 pt-2">
                                {(t.raw(`sections.${section.id}.features`) as string[]).map((feature, i) => (
                                    <li key={i} className="flex items-center gap-3 text-zinc-700 dark:text-zinc-300">
                                        <CheckCircle2 className={`w-5 h-5 ${section.color}`} />
                                        {feature}
                                    </li>
                                ))}
                            </ul>
                        </div>

                        {/* Visual Container */}
                        <div className="flex-1 w-full aspect-video lg:aspect-square max-h-[500px] relative rounded-3xl overflow-hidden bg-zinc-100 dark:bg-zinc-900 border border-zinc-200 dark:border-zinc-800 group cyber-corner lg:neon-border-blue">
                            {/* Unsplash Source Images */}
                            <img
                                src={
                                    section.id === "server" ? "/images/ai-solutions/gpu-cluster.png" :
                                        section.id === "datacenter" ? "/images/ai-solutions/data-center.png" :
                                            "https://images.unsplash.com/photo-1451187580459-43490279c0fa?auto=format&fit=crop&q=80&w=1200"
                                }
                                alt={t(`sections.${section.id}.title`)}
                                className="absolute inset-0 w-full h-full object-cover opacity-100 group-hover:scale-105 transition-all duration-1000"
                            />
                            <div className={`absolute inset-0 bg-gradient-to-br ${section.imgGradient} opacity-40 mix-blend-overlay`} />

                            {/* Scanning line effect for the card */}
                            <div className="absolute inset-0 bg-gradient-to-b from-transparent via-blue-500/5 to-transparent h-1/2 w-full animate-pulse pointer-events-none" />

                            {/* Decorative grid */}
                            <div className="absolute inset-0 bg-grid-white/[0.1] bg-[size:40px_40px]" />

                            {/* Blue shadow glow */}
                            <div className="absolute inset-0 neon-border-blue pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity" />
                        </div>
                    </motion.div>
                ))}
            </div>
        </div>
    );
}

"use client";

import PageHero from "@/components/PageHero";
import { useTranslations } from "next-intl";
import { Mail, MapPin, Phone, Send, Printer } from "lucide-react";
import { motion } from "framer-motion";
import { useState } from "react";

export default function ContactPage() {
    const t = useTranslations("Contact_Page");
    const footerT = useTranslations("Footer");

    // Form state
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isSent, setIsSent] = useState(false);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSubmitting(true);

        const form = e.target as HTMLFormElement;
        const formData = new FormData(form);
        const data = Object.fromEntries(formData.entries());

        const industryLabel = t(`form.industries.${data.industry}`);
        const solutionLabel = t(`form.solutions.${data.solution}`);

        // Construct email body
        const subject = encodeURIComponent(
            t("form.email_subject", {
                name: String(data.name),
                company: String(data.company || 'N/A')
            })
        );
        const body = encodeURIComponent(
            t("form.email_body", {
                name: String(data.name),
                email: String(data.email),
                company: String(data.company || 'N/A'),
                phone: String(data.phone || 'N/A'),
                industry: industryLabel,
                solution: solutionLabel,
                message: String(data.message || t("form.no_message"))
            })
        );

        // Open local mail client
        window.location.href = `mailto:am@noviant.com?subject=${subject}&body=${body}`;

        // Give some visual feedback
        setTimeout(() => {
            setIsSent(true);
            setIsSubmitting(false);
        }, 500);
    };

    const industries = [
        "banking", "education", "fashion", "financial", "government",
        "health", "nonprofit", "retail", "service", "other"
    ];

    const solutions = [
        "business_continuity", "cabling", "cloud", "security", "analytics",
        "infrastructure", "msp", "professional", "staffing", "vciso",
        "virtualization", "voip", "other"
    ];

    return (
        <div className="min-h-screen bg-white dark:bg-black relative overflow-hidden">
            <div className="absolute inset-0 cyber-grid opacity-20 pointer-events-none" />
            <PageHero
                title={t("title")}
                subtitle={t("subtitle")}
                bgGradient="from-blue-900/40 via-black to-blue-900/40"
            />

            <div className="container mx-auto px-4 py-24 relative z-10">
                <div className="grid grid-cols-1 lg:grid-cols-2 gap-16">
                    {/* Contact Info */}
                    <motion.div
                        initial={{ opacity: 0, x: -30 }}
                        whileInView={{ opacity: 1, x: 0 }}
                        transition={{ duration: 0.6 }}
                        viewport={{ once: true }}
                        className="space-y-12 cyber-corner p-10 bg-white/5 backdrop-blur-sm border border-white/10"
                    >
                        <div>
                            <h2 className="text-3xl font-bold mb-6 text-zinc-900 dark:text-white">
                                {t("info.title")}
                            </h2>
                            <p className="text-zinc-600 dark:text-zinc-400 text-lg leading-relaxed mb-8">
                                {t("subtitle")}
                            </p>
                        </div>

                        <div className="grid gap-8">
                            {/* Main Office */}
                            <div className="flex items-start gap-4">
                                <div className="p-3 bg-blue-100 dark:bg-blue-900/30 rounded-full text-blue-600 dark:text-blue-400 shrink-0 neon-glow-blue">
                                    <MapPin className="w-6 h-6" />
                                </div>
                                <div>
                                    <h3 className="font-semibold text-zinc-900 dark:text-white mb-1">
                                        {t("info.address_label")}
                                    </h3>
                                    <p className="text-zinc-600 dark:text-zinc-400">
                                        {footerT("address")}
                                    </p>
                                </div>
                            </div>

                            {/* Main Phone / Fax */}
                            <div className="flex items-start gap-4">
                                <div className="p-3 bg-blue-100 dark:bg-blue-900/30 rounded-full text-blue-600 dark:text-blue-400 shrink-0 neon-glow-blue">
                                    <Phone className="w-6 h-6" />
                                </div>
                                <div>
                                    <h3 className="font-semibold text-zinc-900 dark:text-white mb-1">
                                        {t("info.phone_label")}
                                    </h3>
                                    <div className="space-y-1 text-zinc-600 dark:text-zinc-400">
                                        <p>{t("info.call_label")}: {footerT("phone")}</p>
                                        <p>{t("info.fax_label")}: {t("info.fax_number")}</p>
                                    </div>
                                </div>
                            </div>

                            <hr className="border-zinc-200 dark:border-zinc-800" />

                            {/* Specific Contacts */}
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                <div>
                                    <h4 className="font-bold text-zinc-900 dark:text-white mb-2">{t("info.sales")}</h4>
                                    <p className="text-zinc-600 dark:text-zinc-400 mb-1">(212) 809-6625 x8302</p>
                                    <a href={`mailto:${t("info.sales_email")}`} className="text-blue-600 hover:text-blue-500 transition-colors">
                                        {t("info.sales_email")}
                                    </a>
                                </div>
                                <div>
                                    <h4 className="font-bold text-zinc-900 dark:text-white mb-2">{t("info.support")}</h4>
                                    <p className="text-zinc-600 dark:text-zinc-400 mb-1">(212) 809-6625 x8301</p>
                                    <a href={`mailto:${t("info.support_email")}`} className="text-blue-600 hover:text-blue-500 transition-colors">
                                        {t("info.support_email")}
                                    </a>
                                </div>
                            </div>
                        </div>
                    </motion.div>

                    {/* Contact Form */}
                    <motion.div
                        initial={{ opacity: 0, x: 30 }}
                        whileInView={{ opacity: 1, x: 0 }}
                        transition={{ duration: 0.6 }}
                        viewport={{ once: true }}
                        className="bg-zinc-50 dark:bg-zinc-900/50 p-8 md:p-10 rounded-3xl border border-zinc-200 dark:border-zinc-800 cyber-corner hover:neon-glow-blue transition-all"
                    >
                        <h3 className="text-2xl font-bold mb-6 text-zinc-900 dark:text-white">
                            {t("form.submit")}
                        </h3>
                        {isSent ? (
                            <div className="h-full flex flex-col items-center justify-center text-center py-12">
                                <div className="w-16 h-16 bg-green-100 dark:bg-green-900/30 rounded-full flex items-center justify-center text-green-600 mb-6">
                                    <Send className="w-8 h-8" />
                                </div>
                                <h3 className="text-2xl font-bold text-zinc-900 dark:text-white mb-2">
                                    {t("form.success")}
                                </h3>
                            </div>
                        ) : (
                            <form onSubmit={handleSubmit} className="space-y-4">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <label htmlFor="name" className="text-sm font-medium text-zinc-700 dark:text-zinc-300">
                                            {t("form.name")} *
                                        </label>
                                        <input
                                            id="name"
                                            name="name"
                                            required
                                            type="text"
                                            className="w-full px-4 py-3 rounded-xl bg-white dark:bg-black border border-zinc-200 dark:border-zinc-800 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all text-zinc-900 dark:text-white"
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <label htmlFor="company" className="text-sm font-medium text-zinc-700 dark:text-zinc-300">
                                            {t("form.company")}
                                        </label>
                                        <input
                                            id="company"
                                            name="company"
                                            type="text"
                                            className="w-full px-4 py-3 rounded-xl bg-white dark:bg-black border border-zinc-200 dark:border-zinc-800 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all text-zinc-900 dark:text-white"
                                        />
                                    </div>
                                </div>

                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <label htmlFor="email" className="text-sm font-medium text-zinc-700 dark:text-zinc-300">
                                            {t("form.email")} *
                                        </label>
                                        <input
                                            id="email"
                                            name="email"
                                            required
                                            type="email"
                                            className="w-full px-4 py-3 rounded-xl bg-white dark:bg-black border border-zinc-200 dark:border-zinc-800 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all text-zinc-900 dark:text-white"
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <label htmlFor="phone" className="text-sm font-medium text-zinc-700 dark:text-zinc-300">
                                            {t("form.phone")}
                                        </label>
                                        <input
                                            id="phone"
                                            name="phone"
                                            type="tel"
                                            className="w-full px-4 py-3 rounded-xl bg-white dark:bg-black border border-zinc-200 dark:border-zinc-800 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all text-zinc-900 dark:text-white"
                                        />
                                    </div>
                                </div>

                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <label htmlFor="industry" className="text-sm font-medium text-zinc-700 dark:text-zinc-300">
                                            {t("form.industry")} *
                                        </label>
                                        <select
                                            id="industry"
                                            name="industry"
                                            required
                                            className="w-full px-4 py-3 rounded-xl bg-white dark:bg-black border border-zinc-200 dark:border-zinc-800 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all text-zinc-900 dark:text-white appearance-none"
                                        >
                                            <option value="">{t("form.select_placeholder")}</option>
                                            {industries.map(ind => (
                                                <option key={ind} value={ind}>{t(`form.industries.${ind}`)}</option>
                                            ))}
                                        </select>
                                    </div>
                                    <div className="space-y-2">
                                        <label htmlFor="solution" className="text-sm font-medium text-zinc-700 dark:text-zinc-300">
                                            {t("form.solution")} *
                                        </label>
                                        <select
                                            id="solution"
                                            name="solution"
                                            required
                                            className="w-full px-4 py-3 rounded-xl bg-white dark:bg-black border border-zinc-200 dark:border-zinc-800 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all text-zinc-900 dark:text-white appearance-none"
                                        >
                                            <option value="">{t("form.select_placeholder")}</option>
                                            {solutions.map(sol => (
                                                <option key={sol} value={sol}>{t(`form.solutions.${sol}`)}</option>
                                            ))}
                                        </select>
                                    </div>
                                </div>

                                <div className="space-y-2">
                                    <label htmlFor="message" className="text-sm font-medium text-zinc-700 dark:text-zinc-300">
                                        {t("form.message")}
                                    </label>
                                    <textarea
                                        id="message"
                                        name="message"
                                        rows={4}
                                        className="w-full px-4 py-3 rounded-xl bg-white dark:bg-black border border-zinc-200 dark:border-zinc-800 focus:outline-none focus:ring-2 focus:ring-blue-500 transition-all text-zinc-900 dark:text-white resize-none"
                                    />
                                </div>

                                <button
                                    type="submit"
                                    disabled={isSubmitting}
                                    className="w-full py-4 bg-blue-600 hover:bg-blue-500 text-white font-semibold rounded-xl transition-colors disabled:opacity-50 flex items-center justify-center gap-2"
                                >
                                    {isSubmitting ? t("form.sending") : t("form.submit")}
                                    {!isSubmitting && <Send className="w-4 h-4" />}
                                </button>
                            </form>
                        )}
                    </motion.div>
                </div>
            </div>
        </div>
    );
}

